import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Вступ у Fabric та створення модів","description":"Короткий вступ до Fabric і створення модів у Minecraft: Java Edition.","frontmatter":{"title":"Вступ у Fabric та створення модів","description":"Короткий вступ до Fabric і створення модів у Minecraft: Java Edition.","authors":["IMB11","itsmiir"],"authors-nogithub":["basil4088"],"files":[]},"headers":[],"relativePath":"uk_ua/1.21.4/develop/getting-started/introduction-to-fabric-and-modding.md","filePath":"versions/1.21.4/translated/uk_ua/develop/getting-started/introduction-to-fabric-and-modding.md","lastUpdated":1760721669000}`);var a={name:`uk_ua/1.21.4/develop/getting-started/introduction-to-fabric-and-modding.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Вступ у Fabric та створення модів <a class="header-anchor" href="#h1" aria-label="Permalink to “Вступ у Fabric та створення модів”">​</a></h1><h2 id="prerequisites" tabindex="-1">Передумови <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Передумови”">​</a></h2><p>Перш ніж почати, ви повинні мати базове уявлення про розробку на Java та розуміння об’єктноорієнтованого програмування (ООП).</p><p>Якщо ви не знайомі з цими поняттями, ви можете ознайомитися з деякими підручниками з Java та ООП, перш ніж почати створення модів. Ось деякі з ресурсів, які ви можете використовувати для вивчення Java та ООП:</p><ul><li><a href="https://www.w3schools.com/java/" target="_blank" rel="noreferrer">W3: Java Tutorials</a></li><li><a href="https://www.codecademy.com/learn/learn-java" target="_blank" rel="noreferrer">Codecademy: Learn Java</a></li><li><a href="https://www.w3schools.com/java/java_oop.asp" target="_blank" rel="noreferrer">W3: Java OOP</a></li><li><a href="https://medium.com/@Adekola_Olawale/beginners-guide-to-object-oriented-programming-a94601ea2fbd" target="_blank" rel="noreferrer">Середина: Вступ до ООП</a></li></ul><h3 id="terminology" tabindex="-1">Термінологія <a class="header-anchor" href="#terminology" aria-label="Permalink to “Термінологія”">​</a></h3><p>Перш ніж ми почнемо, розгляньмо деякі терміни, які ви зустрінете під час створення модів за допомогою Fabric:</p><ul><li><strong>Мод</strong>: модифікація гри, додавання нових функцій або зміна існуючих.</li><li><strong>завантадувач модів</strong>: інструмент, який завантажує моди в гру, наприклад Fabric Loader.</li><li><strong>Mixin</strong>: інструмент для модифікації коду гри під час виконання – див. <a href="https://fabricmc.net/wiki/tutorial:mixin_introduction" target="_blank" rel="noreferrer">знайомство з міксинами</a> для отримання додаткової інформації.</li><li><strong>Gradle</strong>: інструмент автоматизації збірки, який використовується для створення та компіляції модів, використовується Fabric для створення модів.</li><li><strong>Мапування</strong>: набір мапування, які мапують обфусцований код у зрозумілий людині код.</li><li><strong>Обфускація</strong>: процес створення коду складним для розуміння, який використовується Mojang для захисту коду Minecraft.</li><li><strong>Перемапування</strong>: процес мапування заплутаного коду в код, зрозумілий людині.</li></ul><h2 id="what-is-fabric" tabindex="-1">Що таке Fabric? <a class="header-anchor" href="#what-is-fabric" aria-label="Permalink to “Що таке Fabric?”">​</a></h2><p>Fabric — це легкий набір інструментів модифікації для Minecraft: Java Edition.</p><p>Він розроблений як проста та зручна у використанні платформа для створення модів. Fabric — це проєкт, керований спільнотою, і він має відкритий вихідний код, що означає, що кожен може зробити свій внесок у проєкт.</p><p>Ви повинні знати про чотири основні компоненти Fabric:</p><ul><li><strong>Fabric Loader</strong>: гнучкий незалежний від платформи завантажувач модів, розроблений для Minecraft та інших ігор і програм.</li><li><strong>Fabric Loom</strong>: плаґін Gradle, який дозволяє розробникам легко розробляти та налагоджувати моди.</li><li><strong>Fabric API</strong>: набір API та інструментів, які розробники модів використовують під час створення модів.</li><li><strong>Yarn</strong>: набір відкритого мапування Minecraft, безплатний для всіх за ліцензією Creative Commons Zero.</li></ul><h2 id="why-is-fabric-necessary-to-mod-minecraft" tabindex="-1">Чому Fabric необхідний для модифікації Minecraft? <a class="header-anchor" href="#why-is-fabric-necessary-to-mod-minecraft" aria-label="Permalink to “Чому Fabric необхідний для модифікації Minecraft?”">​</a></h2><blockquote><p>Модифікація — це процес модифікації гри з метою зміни її поведінки або додавання нових функцій — у випадку з Minecraft це може бути що завгодно: від додавання нових предметів, блоків або сутностей до зміни механіки гри або додавання нових режимів гри.</p></blockquote><p>Minecraft: Java Edition обфускований Mojang, що ускладнює модифікацію. Однак за допомогою таких інструментів модифікації, як Fabric, модифікувати стає набагато легше. Існує кілька систем мапування, які можуть допомогти в цьому процесі.</p><p>Loom перетворює обфусцований код у формат, зрозумілий людині, використання мапування, полегшує розробникам модів розуміння та змінення коду гри. Yarn є популярним і чудовим вибором мапування для цього, але існують і інші варіанти. Кожен проєкт мапування може мати свої сильні сторони або напрямок.</p><p>Loom дозволяє легко розробляти та компілювати моди на основі перемапованого коду, а Fabric Loader дозволяє завантажувати ці моди в гру.</p><h2 id="what-does-fabric-api-provide-and-why-is-it-needed" tabindex="-1">Що надає Fabric API та навіщо він потрібен? <a class="header-anchor" href="#what-does-fabric-api-provide-and-why-is-it-needed" aria-label="Permalink to “Що надає Fabric API та навіщо він потрібен?”">​</a></h2><blockquote><p>Fabric API — це набір API та інструментів, які розробники модів використовують під час створення модів.</p></blockquote><p>Fabric API надає широкий набір API, які створюються на основі існуючої функціональності Minecraft - наприклад, надають нові хуки та події для використання розробниками модів, або надають нові утиліти та інструменти, щоб полегшити модифікацію - такі як розширювачі транзитивного доступу та можливість отримати доступ до внутрішніх реєстрів, таких як реєстр компостованих предметів.</p><p>Попри те, що Fabric API пропонує потужні функції, деякі завдання, як-от базова реєстрація блоків, можна виконати без нього за допомогою ванілльних API.</p>`,22)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};